const { app, BrowserWindow, shell, ipcMain } = require("electron");
const path = require("path");
const axios = require("axios");

let store;
const cacheRows = [];
let cacheNextId = 1;

function getNativeIconPath() {
  return app.isPackaged
    ? path.join(process.resourcesPath, "assests", "icon.ico")
    : path.join(__dirname, "..", "..", "assests", "icon.ico");
}

function createWindow() {
  const win = new BrowserWindow({
    width: 1280,
    height: 820,
    icon: getNativeIconPath(),
    webPreferences: {
      preload: path.join(__dirname, "preload.cjs"),
      contextIsolation: true,
      nodeIntegration: false,
    },
  });

  const devUrl = process.env.VITE_DEV_SERVER_URL || "http://localhost:5173";
  if (app.isPackaged) {
    win.loadFile(path.join(__dirname, "../dist/index.html"));
  } else {
    win.loadURL(devUrl);
  }
}

app.whenReady().then(() => {
  return import("electron-store").then(({ default: Store }) => {
    store = new Store({
      name: "email-validator-settings",
      defaults: {
        authToken: "",
        user: null,
        rememberMe: false,
        autoUpdate: true,
        saveHistory: true,
      },
    });

    createWindow();
  });
}).then(() => {

  app.on("activate", () => {
    if (BrowserWindow.getAllWindows().length === 0) createWindow();
  });
});

app.on("window-all-closed", () => {
  if (process.platform !== "darwin") app.quit();
});

ipcMain.handle("store:get", (_event, key) => store.get(key));
ipcMain.handle("store:set", (_event, { key, value }) => {
  store.set(key, value);
  return true;
});
ipcMain.handle("store:delete", (_event, key) => {
  store.delete(key);
  return true;
});
ipcMain.handle("external:open", (_event, url) => shell.openExternal(url));
ipcMain.handle("http:request", async (_event, config) => {
  try {
    const response = await axios({
      baseURL: config.baseURL,
      method: config.method,
      url: config.url,
      params: config.params,
      data: config.data,
      headers: config.headers,
      timeout: config.timeout,
    });

    return {
      ok: true,
      status: response.status,
      statusText: response.statusText,
      headers: response.headers,
      data: response.data,
    };
  } catch (error) {
    return {
      ok: false,
      message: error.message || "Request failed",
      status: error.response?.status || 0,
      statusText: error.response?.statusText || "",
      headers: error.response?.headers || {},
      data: error.response?.data ?? null,
    };
  }
});
ipcMain.handle("cache:add", (_event, row) => {
  const saved = {
    id: cacheNextId++,
    email: row.email,
    isValid: Boolean(row.isValid),
    reason: row.reason || "",
    source: row.source || "local",
    createdAt: row.createdAt,
  };
  cacheRows.push(saved);
  return saved.id;
});
ipcMain.handle("cache:list", (_event, limit = 100) => {
  const safeLimit = Number.isFinite(limit) ? Math.max(0, Math.floor(limit)) : 100;
  return cacheRows.slice(-safeLimit).reverse();
});
